+/*
+ * hooks.c — runtime hook management, validation, and dispatch
+ *
+ * Implements the hook contract from asx_config.h:
+ *   - Hook initialization with safe defaults (malloc-based allocator, stderr log)
+ *   - Deterministic mode validation (forbids ambient entropy, requires logical clock)
+ *   - Allocator seal for hardened/no-allocation profiles
+ *   - Hook-backed runtime helpers that dispatch through the active hook table
+ *
+ * SPDX-License-Identifier: MIT
+ */
+
+#include <asx/asx_config.h>
+#include <stdlib.h>
+#include <stdio.h>
+#include <string.h>
+
+/* ------------------------------------------------------------------ */
+/* Default hook implementations                                       */
+/* ------------------------------------------------------------------ */
+
+static void *default_malloc(void *ctx, size_t size) {
+    (void)ctx;
+    return malloc(size);
+}
+
+static void *default_realloc(void *ctx, void *ptr, size_t size) {
+    (void)ctx;
+    return realloc(ptr, size);
+}
+
+static void default_free(void *ctx, void *ptr) {
+    (void)ctx;
+    free(ptr);
+}
+
+static void default_log_write(void *ctx, int level, const char *message) {
+    (void)ctx;
+    fprintf(stderr, "[asx:%d] %s\n", level, message);
+}
+
+/* ------------------------------------------------------------------ */
+/* Global hook state                                                  */
+/* ------------------------------------------------------------------ */
+
+static asx_runtime_hooks g_hooks;
+static int g_hooks_installed = 0;
+
+/* ------------------------------------------------------------------ */
+/* Hook initialization                                                */
+/* ------------------------------------------------------------------ */
+
+asx_status asx_runtime_hooks_init(asx_runtime_hooks *hooks) {
+    if (!hooks) return ASX_E_INVALID_ARGUMENT;
+    memset(hooks, 0, sizeof(*hooks));
+
+    /* Default allocator: stdlib malloc/realloc/free */
+    hooks->allocator.malloc_fn  = default_malloc;
+    hooks->allocator.realloc_fn = default_realloc;
+    hooks->allocator.free_fn    = default_free;
+
+    /* Default log: stderr */
+    hooks->log.write_fn = default_log_write;
+
+    /* Clock, entropy, reactor: left as NULL — must be set by user
+     * or validated before use. */
+
+    hooks->deterministic_seeded_prng = 0;
+    hooks->allocator_sealed = 0;
+
+    return ASX_OK;
+}
+
+/* ------------------------------------------------------------------ */
+/* Hook validation                                                    */
+/* ------------------------------------------------------------------ */
+
+asx_status asx_runtime_hooks_validate(const asx_runtime_hooks *hooks,
+                                       int deterministic_mode) {
+    if (!hooks) return ASX_E_INVALID_ARGUMENT;
+
+    /* Allocator is mandatory */
+    if (!hooks->allocator.malloc_fn || !hooks->allocator.free_fn)
+        return ASX_E_INVALID_ARGUMENT;
+
+    if (deterministic_mode) {
+        /* Deterministic mode requires a logical clock */
+        if (!hooks->clock.logical_now_ns_fn)
+            return ASX_E_INVALID_STATE;
+
+        /* Deterministic mode forbids ambient entropy unless seeded PRNG is configured */
+        if (hooks->entropy.random_u64_fn && !hooks->deterministic_seeded_prng)
+            return ASX_E_INVALID_STATE;
+
+        /* Ghost reactor required if reactor is configured in deterministic mode */
+        if (hooks->reactor.wait_fn && !hooks->reactor.ghost_wait_fn)
+            return ASX_E_INVALID_STATE;
+    } else {
+        /* Live mode needs a real clock */
+        if (!hooks->clock.now_ns_fn)
+            return ASX_E_INVALID_STATE;
+    }
+
+    return ASX_OK;
+}
+
+/* ------------------------------------------------------------------ */
+/* Hook installation and retrieval                                    */
+/* ------------------------------------------------------------------ */
+
+asx_status asx_runtime_set_hooks(const asx_runtime_hooks *hooks) {
+    if (!hooks) return ASX_E_INVALID_ARGUMENT;
+    g_hooks = *hooks;
+    g_hooks_installed = 1;
+    return ASX_OK;
+}
+
+const asx_runtime_hooks *asx_runtime_get_hooks(void) {
+    if (!g_hooks_installed) return NULL;
+    return &g_hooks;
+}
+
+/* ------------------------------------------------------------------ */
+/* Allocator seal                                                     */
+/* ------------------------------------------------------------------ */
+
+asx_status asx_runtime_seal_allocator(void) {
+    if (!g_hooks_installed) return ASX_E_INVALID_STATE;
+    if (g_hooks.allocator_sealed) return ASX_OK; /* idempotent */
+    g_hooks.allocator_sealed = 1;
+    return ASX_OK;
+}
+
+/* ------------------------------------------------------------------ */
+/* Hook-backed runtime helpers                                        */
+/* ------------------------------------------------------------------ */
+
+asx_status asx_runtime_alloc(size_t size, void **out_ptr) {
+    void *p;
+    if (!out_ptr) return ASX_E_INVALID_ARGUMENT;
+    if (!g_hooks_installed) return ASX_E_INVALID_STATE;
+    if (g_hooks.allocator_sealed) return ASX_E_RESOURCE_EXHAUSTED;
+    if (!g_hooks.allocator.malloc_fn) return ASX_E_INVALID_STATE;
+
+    p = g_hooks.allocator.malloc_fn(g_hooks.allocator.ctx, size);
+    if (!p) return ASX_E_RESOURCE_EXHAUSTED;
+    *out_ptr = p;
+    return ASX_OK;
+}
+
+asx_status asx_runtime_realloc(void *ptr, size_t size, void **out_ptr) {
+    void *p;
+    if (!out_ptr) return ASX_E_INVALID_ARGUMENT;
+    if (!g_hooks_installed) return ASX_E_INVALID_STATE;
+    if (g_hooks.allocator_sealed) return ASX_E_RESOURCE_EXHAUSTED;
+    if (!g_hooks.allocator.realloc_fn) return ASX_E_INVALID_STATE;
+
+    p = g_hooks.allocator.realloc_fn(g_hooks.allocator.ctx, ptr, size);
+    if (!p && size > 0) return ASX_E_RESOURCE_EXHAUSTED;
+    *out_ptr = p;
+    return ASX_OK;
+}
+
+asx_status asx_runtime_free(void *ptr) {
+    if (!g_hooks_installed) return ASX_E_INVALID_STATE;
+    if (!g_hooks.allocator.free_fn) return ASX_E_INVALID_STATE;
+    g_hooks.allocator.free_fn(g_hooks.allocator.ctx, ptr);
+    return ASX_OK;
+}
+
+asx_status asx_runtime_now_ns(asx_time *out_now) {
+    if (!out_now) return ASX_E_INVALID_ARGUMENT;
+    if (!g_hooks_installed) return ASX_E_INVALID_STATE;
+
+#if ASX_DETERMINISTIC
+    if (g_hooks.clock.logical_now_ns_fn) {
+        *out_now = g_hooks.clock.logical_now_ns_fn(g_hooks.clock.ctx);
+        return ASX_OK;
+    }
+#endif
+    if (g_hooks.clock.now_ns_fn) {
+        *out_now = g_hooks.clock.now_ns_fn(g_hooks.clock.ctx);
+        return ASX_OK;
+    }
+    return ASX_E_INVALID_STATE;
+}
+
+asx_status asx_runtime_random_u64(uint64_t *out_value) {
+    if (!out_value) return ASX_E_INVALID_ARGUMENT;
+    if (!g_hooks_installed) return ASX_E_INVALID_STATE;
+
+#if ASX_DETERMINISTIC
+    /* In deterministic mode, entropy is forbidden unless seeded PRNG */
+    if (!g_hooks.deterministic_seeded_prng)
+        return ASX_E_INVALID_STATE;
+#endif
+    if (!g_hooks.entropy.random_u64_fn) return ASX_E_INVALID_STATE;
+    *out_value = g_hooks.entropy.random_u64_fn(g_hooks.entropy.ctx);
+    return ASX_OK;
+}
+
+asx_status asx_runtime_reactor_wait(uint32_t timeout_ms,
+                                     uint32_t *out_ready_count,
+                                     uint64_t logical_step) {
+    if (!out_ready_count) return ASX_E_INVALID_ARGUMENT;
+    if (!g_hooks_installed) return ASX_E_INVALID_STATE;
+
+#if ASX_DETERMINISTIC
+    if (g_hooks.reactor.ghost_wait_fn) {
+        return g_hooks.reactor.ghost_wait_fn(g_hooks.reactor.ctx,
+                                              logical_step, out_ready_count);
+    }
+#endif
+    if (g_hooks.reactor.wait_fn) {
+        return g_hooks.reactor.wait_fn(g_hooks.reactor.ctx,
+                                        timeout_ms, out_ready_count);
+    }
+    return ASX_E_INVALID_STATE;
+}
+
+asx_status asx_runtime_log_write(int level, const char *message) {
+    if (!g_hooks_installed) return ASX_E_INVALID_STATE;
+    if (!g_hooks.log.write_fn) return ASX_OK; /* silent if no log hook */
+    g_hooks.log.write_fn(g_hooks.log.ctx, level, message);
+    return ASX_OK;
+}
+
+/* ------------------------------------------------------------------ */
+/* Config initialization                                              */
+/* ------------------------------------------------------------------ */
+
+void asx_runtime_config_init(asx_runtime_config *cfg) {
+    if (!cfg) return;
+    memset(cfg, 0, sizeof(*cfg));
+    cfg->size = (uint32_t)sizeof(*cfg);
+    cfg->wait_policy = ASX_WAIT_YIELD;
+    cfg->leak_response = ASX_LEAK_LOG;
+    cfg->finalizer_poll_budget = 100;
+    cfg->finalizer_time_budget_ns = (uint64_t)5000000000ULL; /* 5 seconds */
+    cfg->finalizer_escalation = ASX_FINALIZER_BOUNDED_LOG;
+    cfg->max_cancel_chain_depth = 16;
+    cfg->max_cancel_chain_memory = 4096;
+}

@@ -0,0 +1,253 @@
+/*
+ * test_hooks.c — unit tests for runtime hook contract
+ *
+ * Tests: initialization, validation (deterministic/live), allocator seal,
+ * hook dispatch, and forbidden entropy in deterministic mode.
+ *
+ * SPDX-License-Identifier: MIT
+ */
+
+#include "../../test_harness.h"
+#include <asx/asx_config.h>
+#include <stdlib.h>
+#include <string.h>
+
+/* ------------------------------------------------------------------ */
+/* Test hook implementations                                          */
+/* ------------------------------------------------------------------ */
+
+static int alloc_count = 0;
+static int free_count = 0;
+static int log_count = 0;
+static asx_time fake_time = 0;
+static uint64_t fake_entropy = 42;
+
+static void *test_malloc(void *ctx, size_t size) {
+    (void)ctx;
+    alloc_count++;
+    return malloc(size);
+}
+
+static void *test_realloc(void *ctx, void *ptr, size_t size) {
+    (void)ctx;
+    return realloc(ptr, size);
+}
+
+static void test_free(void *ctx, void *ptr) {
+    (void)ctx;
+    free_count++;
+    free(ptr);
+}
+
+static asx_time test_clock(void *ctx) {
+    (void)ctx;
+    return 1000000000ULL; /* 1 second */
+}
+
+static asx_time test_logical_clock(void *ctx) {
+    (void)ctx;
+    return fake_time;
+}
+
+static uint64_t test_entropy(void *ctx) {
+    (void)ctx;
+    return fake_entropy;
+}
+
+static void test_log(void *ctx, int level, const char *message) {
+    (void)ctx; (void)level; (void)message;
+    log_count++;
+}
+
+/* ------------------------------------------------------------------ */
+/* Tests                                                              */
+/* ------------------------------------------------------------------ */
+
+TEST(hooks_init_defaults) {
+    asx_runtime_hooks hooks;
+    asx_status s = asx_runtime_hooks_init(&hooks);
+    ASSERT_EQ(s, ASX_OK);
+    /* Default allocator must be set */
+    ASSERT_TRUE(hooks.allocator.malloc_fn != NULL);
+    ASSERT_TRUE(hooks.allocator.free_fn != NULL);
+    /* Default log must be set */
+    ASSERT_TRUE(hooks.log.write_fn != NULL);
+    /* Clock/entropy/reactor not set by default */
+    ASSERT_TRUE(hooks.clock.now_ns_fn == NULL);
+    ASSERT_TRUE(hooks.entropy.random_u64_fn == NULL);
+    ASSERT_TRUE(hooks.reactor.wait_fn == NULL);
+    /* Flags clear */
+    ASSERT_EQ(hooks.deterministic_seeded_prng, (uint8_t)0);
+    ASSERT_EQ(hooks.allocator_sealed, (uint8_t)0);
+}
+
+TEST(hooks_init_null_rejected) {
+    ASSERT_EQ(asx_runtime_hooks_init(NULL), ASX_E_INVALID_ARGUMENT);
+}
+
+TEST(hooks_validate_live_needs_clock) {
+    asx_runtime_hooks hooks;
+    asx_runtime_hooks_init(&hooks);
+    /* No clock set → validation fails for live mode */
+    ASSERT_EQ(asx_runtime_hooks_validate(&hooks, 0), ASX_E_INVALID_STATE);
+    /* Set clock → passes */
+    hooks.clock.now_ns_fn = test_clock;
+    ASSERT_EQ(asx_runtime_hooks_validate(&hooks, 0), ASX_OK);
+}
+
+TEST(hooks_validate_deterministic_needs_logical_clock) {
+    asx_runtime_hooks hooks;
+    asx_runtime_hooks_init(&hooks);
+    /* Only wall clock set → fails in deterministic mode */
+    hooks.clock.now_ns_fn = test_clock;
+    ASSERT_EQ(asx_runtime_hooks_validate(&hooks, 1), ASX_E_INVALID_STATE);
+    /* Set logical clock → passes */
+    hooks.clock.logical_now_ns_fn = test_logical_clock;
+    ASSERT_EQ(asx_runtime_hooks_validate(&hooks, 1), ASX_OK);
+}
+
+TEST(hooks_validate_deterministic_forbids_ambient_entropy) {
+    asx_runtime_hooks hooks;
+    asx_runtime_hooks_init(&hooks);
+    hooks.clock.logical_now_ns_fn = test_logical_clock;
+    /* Entropy without seeded PRNG flag → rejected */
+    hooks.entropy.random_u64_fn = test_entropy;
+    hooks.deterministic_seeded_prng = 0;
+    ASSERT_EQ(asx_runtime_hooks_validate(&hooks, 1), ASX_E_INVALID_STATE);
+    /* Set seeded PRNG flag → passes */
+    hooks.deterministic_seeded_prng = 1;
+    ASSERT_EQ(asx_runtime_hooks_validate(&hooks, 1), ASX_OK);
+}
+
+TEST(hooks_validate_missing_allocator) {
+    asx_runtime_hooks hooks;
+    memset(&hooks, 0, sizeof(hooks));
+    hooks.clock.now_ns_fn = test_clock;
+    /* No allocator → rejected */
+    ASSERT_EQ(asx_runtime_hooks_validate(&hooks, 0), ASX_E_INVALID_ARGUMENT);
+}
+
+TEST(hooks_install_and_retrieve) {
+    asx_runtime_hooks hooks;
+    const asx_runtime_hooks *active;
+    asx_runtime_hooks_init(&hooks);
+    hooks.clock.now_ns_fn = test_clock;
+
+    ASSERT_EQ(asx_runtime_set_hooks(&hooks), ASX_OK);
+    active = asx_runtime_get_hooks();
+    ASSERT_TRUE(active != NULL);
+    ASSERT_TRUE(active->allocator.malloc_fn != NULL);
+    ASSERT_TRUE(active->clock.now_ns_fn == test_clock);
+}
+
+TEST(hooks_alloc_dispatch) {
+    asx_runtime_hooks hooks;
+    void *ptr = NULL;
+    asx_runtime_hooks_init(&hooks);
+    hooks.allocator.malloc_fn = test_malloc;
+    hooks.allocator.realloc_fn = test_realloc;
+    hooks.allocator.free_fn = test_free;
+    hooks.clock.now_ns_fn = test_clock;
+    asx_runtime_set_hooks(&hooks);
+
+    alloc_count = 0;
+    free_count = 0;
+
+    ASSERT_EQ(asx_runtime_alloc(64, &ptr), ASX_OK);
+    ASSERT_TRUE(ptr != NULL);
+    ASSERT_EQ(alloc_count, 1);
+
+    ASSERT_EQ(asx_runtime_free(ptr), ASX_OK);
+    ASSERT_EQ(free_count, 1);
+}
+
+TEST(hooks_allocator_seal) {
+    asx_runtime_hooks hooks;
+    void *ptr = NULL;
+    asx_runtime_hooks_init(&hooks);
+    hooks.clock.now_ns_fn = test_clock;
+    asx_runtime_set_hooks(&hooks);
+
+    /* Alloc works before seal */
+    ASSERT_EQ(asx_runtime_alloc(32, &ptr), ASX_OK);
+    ASSERT_TRUE(ptr != NULL);
+    asx_runtime_free(ptr);
+    ptr = NULL;
+
+    /* Seal allocator */
+    ASSERT_EQ(asx_runtime_seal_allocator(), ASX_OK);
+
+    /* Alloc rejected after seal */
+    ASSERT_EQ(asx_runtime_alloc(32, &ptr), ASX_E_RESOURCE_EXHAUSTED);
+
+    /* Seal is idempotent */
+    ASSERT_EQ(asx_runtime_seal_allocator(), ASX_OK);
+}
+
+TEST(hooks_clock_dispatch) {
+    asx_runtime_hooks hooks;
+    asx_time now = 0;
+    asx_runtime_hooks_init(&hooks);
+    hooks.clock.now_ns_fn = test_clock;
+    asx_runtime_set_hooks(&hooks);
+
+    ASSERT_EQ(asx_runtime_now_ns(&now), ASX_OK);
+    ASSERT_EQ(now, (asx_time)1000000000ULL);
+}
+
+TEST(hooks_log_dispatch) {
+    asx_runtime_hooks hooks;
+    asx_runtime_hooks_init(&hooks);
+    hooks.clock.now_ns_fn = test_clock;
+    hooks.log.write_fn = test_log;
+    asx_runtime_set_hooks(&hooks);
+
+    log_count = 0;
+    ASSERT_EQ(asx_runtime_log_write(0, "test message"), ASX_OK);
+    ASSERT_EQ(log_count, 1);
+}
+
+TEST(hooks_config_init) {
+    asx_runtime_config cfg;
+    asx_runtime_config_init(&cfg);
+    ASSERT_EQ(cfg.size, (uint32_t)sizeof(asx_runtime_config));
+    ASSERT_EQ(cfg.wait_policy, ASX_WAIT_YIELD);
+    ASSERT_EQ(cfg.leak_response, ASX_LEAK_LOG);
+    ASSERT_EQ(cfg.finalizer_poll_budget, (uint32_t)100);
+    ASSERT_EQ(cfg.finalizer_time_budget_ns, (uint64_t)5000000000ULL);
+    ASSERT_EQ(cfg.finalizer_escalation, ASX_FINALIZER_BOUNDED_LOG);
+    ASSERT_EQ(cfg.max_cancel_chain_depth, (uint16_t)16);
+    ASSERT_EQ(cfg.max_cancel_chain_memory, (uint32_t)4096);
+}
+
+TEST(hooks_entropy_forbidden_without_prng) {
+    asx_runtime_hooks hooks;
+    uint64_t val = 0;
+    asx_runtime_hooks_init(&hooks);
+    hooks.clock.now_ns_fn = test_clock;
+    hooks.clock.logical_now_ns_fn = test_logical_clock;
+    /* No entropy hook installed */
+    asx_runtime_set_hooks(&hooks);
+
+    /* Should fail: no entropy function */
